40	impl TrayHandle {
41	    /// Spawn the tray on a dedicated tokio thread. Returns immediately.
42	    /// Returns `None` if the D-Bus session bus is not available (e.g. headless CI).
43	    pub fn spawn() -> Option<Self> {
44	        let open_window = Arc::new(AtomicBool::new(false));
45	        let open_window_clone = Arc::clone(&open_window);
46	
47	        let (tx, rx) = std::sync::mpsc::channel::<Result<(), String>>();
48	
49	        let thread = std::thread::Builder::new()
50	            .name("tray-tokio".into())
51	            .spawn(move || {
52	                let rt = match tokio::runtime::Builder::new_current_thread()
53	                    .enable_all()
54	                    .build()
55	                {
56	                    Ok(rt) => rt,
57	                    Err(e) => {
58	                        let _ = tx.send(Err(format!("tokio runtime build failed: {e}")));
59	                        return;
60	                    }
61	                };
62	
63	                rt.block_on(async move {
64	                    let tray = VibeTray {
65	                        open_window: Arc::clone(&open_window_clone),
66	                        state: Arc::new(Mutex::new(TrayState::default())),
67	                    };
68	                    let state_ref = Arc::clone(&tray.state);
69	
70	                    match tray.spawn().await {
71	                        Ok(handle) => {
72	                            let _ = tx.send(Ok(()));
73	
74	                            // Spawn the poll loop inside the same tokio runtime.
75	                            let poll_handle = handle.clone();
76	                            tokio::spawn(async move {
77	                                loop {
78	                                    tokio::time::sleep(tokio::time::Duration::from_secs(1)).await;
79	
80	                                    let status = query_status();
81	                                    let new_daemon_state = status.as_ref().map(|s| s.state.clone());
82	                                    let new_active_mode = status.as_ref().map(|s| s.active_mode.clone());
83	                                    let new_active_profile = status.and_then(|s| s.active_profile);
84	                                    // Read profile list from disk on each tick — cheap stat, no daemon needed.
85	                                    let new_profiles = load_profiles();
86	
87	                                    // Only push a D-Bus update when the visible state actually changed.
88	                                    let changed = {
89	                                        let s = state_ref.lock().await;
90	                                        s.daemon_state != new_daemon_state
91	                                            || s.active_profile != new_active_profile
92	                                            || s.profiles != new_profiles
93	                                            || s.active_mode != new_active_mode
94	                                    };
95	
96	                                    if changed {
97	                                        poll_handle
98	                                            .update(|tray: &mut VibeTray| {
99	                                                if let Ok(mut s) = tray.state.try_lock() {
100	                                                    s.daemon_state = new_daemon_state.clone();
101	                                                    s.active_profile = new_active_profile.clone();
102	                                                    s.profiles = new_profiles.clone();
103	                                                    s.active_mode = new_active_mode.clone();
104	                                                }
105	                                            })
106	                                            .await;
107	                                    }
108	                                }
109	                            });
110	
111	                            std::future::pending::<()>().await;
112	                        }
113	                        Err(e) => {
114	                            let _ = tx.send(Err(format!("tray spawn failed: {e}")));
115	                        }
116	                    }
117	                });
118	            })
119	            .ok()?;
120	
121	        match rx.recv() {
122	            Ok(Ok(())) => Some(TrayHandle {
123	                open_window,
124	                _thread: thread,
125	            }),
126	            Ok(Err(e)) => {
127	                tracing::warn!(reason = %e, "System tray unavailable");
128	                None
129	            }
130	            Err(_) => None,
131	        }
132	    }
133	
134	    /// Returns true (and resets the flag) if the tray requested the window to open.
135	    pub fn take_open_request(&self) -> bool {
136	        self.open_window.swap(false, Ordering::AcqRel)
137	    }
138	}
