216	            }
217	            .into(),
218	        );
219	
220	        items.push(MenuItem::Separator);
221	
222	        if daemon_running {
223	            let mute_label = if is_muted { "Unmute" } else { "Mute" };
224	            let mute_icon = if is_muted {
225	                "audio-input-microphone"
226	            } else {
227	                "audio-input-microphone-muted"
228	            };
229	            items.push(
230	                StandardItem {
231	                    label: mute_label.into(),
232	                    icon_name: mute_icon.into(),
233	                    activate: Box::new(move |_this: &mut Self| {
234	                        let cmd = if is_muted {
235	                            ControlRequest::Unmute
236	                        } else {
237	                            ControlRequest::Mute
238	                        };
239	                        // Fire-and-forget on a fresh thread — ksni callbacks must not block.
240	                        std::thread::spawn(move || {
241	                            let _ = send_command(cmd);
242	                        });
243	                    }),
244	                    ..Default::default()
245	                }
246	                .into(),
247	            );
248	            items.push(MenuItem::Separator);
249	        }
250	
251	        // Profile switcher submenu — always shown, disabled when daemon is not running.
252	        let profile_submenu: Vec<MenuItem<Self>> = state
253	            .profiles
254	            .iter()
255	            .map(|name| {
256	                let is_active = state.active_profile.as_deref() == Some(name.as_str());
257	                let name_clone = name.clone();
258	                CheckmarkItem {
259	                    label: name.clone(),
260	                    checked: is_active,
261	                    enabled: daemon_running,
262	                    activate: Box::new(move |_this: &mut Self| {
263	                        let req = ControlRequest::SwitchProfile {
264	                            name: name_clone.clone(),
265	                        };
266	                        std::thread::spawn(move || {
267	                            let _ = send_command(req);
268	                        });
269	                    }),
270	                    ..Default::default()
271	                }
272	                .into()
273	            })
274	            .collect();
275	
276	        items.push(
277	            SubMenu {
278	                label: "Profiles".into(),
279	                icon_name: "folder".into(),
280	                enabled: !state.profiles.is_empty(),
281	                submenu: profile_submenu,
282	                ..Default::default()
283	            }
284	            .into(),
285	        );
286	
287	        // Mode switcher submenu — PTT vs Wake word.
288	        let is_ptt = state.active_mode == Some(ActivationMode::Ptt);
289	        let is_wake = state.active_mode == Some(ActivationMode::Wake);
290	        let mode_submenu: Vec<MenuItem<Self>> = vec![
291	            CheckmarkItem {
292	                label: "Push-to-talk".into(),
293	                checked: is_ptt,
294	                enabled: daemon_running,
295	                activate: Box::new(move |_this: &mut Self| {
296	                    std::thread::spawn(move || {
297	                        let _ = send_command(ControlRequest::SetMode {
298	                            mode: ActivationMode::Ptt,
299	                        });
300	                    });
301	                }),
302	                ..Default::default()
303	            }
304	            .into(),
305	            CheckmarkItem {
306	                label: "Wake word".into(),
307	                checked: is_wake,
308	                enabled: daemon_running,
309	                activate: Box::new(move |_this: &mut Self| {
310	                    std::thread::spawn(move || {
311	                        let _ = send_command(ControlRequest::SetMode {
312	                            mode: ActivationMode::Wake,
313	                        });
314	                    });
315	                }),
316	                ..Default::default()
317	            }
318	            .into(),
319	        ];
320	
321	        items.push(
322	            SubMenu {
323	                label: "Mode".into(),
324	                submenu: mode_submenu,
325	                ..Default::default()
326	            }
327	            .into(),
