            tooltip_description_for(Some(&DaemonState::Recording), Some(&ActivationMode::Wake));
        let none = tooltip_description_for(Some(&DaemonState::Recording), None);
        assert_eq!(ptt, wake);
        assert_eq!(ptt, none);
    }

