42	impl TrayHandle {
43	    /// Spawn the tray on a dedicated tokio thread. Returns immediately.
44	    /// Returns `None` if the D-Bus session bus is not available (e.g. headless CI).
45	    pub fn spawn() -> Option<Self> {
46	        let open_window = Arc::new(AtomicBool::new(false));
47	        let open_window_clone = Arc::clone(&open_window);
48	        let quit_window = Arc::new(AtomicBool::new(false));
49	        let quit_window_clone = Arc::clone(&quit_window);
50	
51	        let (tx, rx) = std::sync::mpsc::channel::<Result<(), String>>();
52	
53	        let thread = std::thread::Builder::new()
54	            .name("tray-tokio".into())
55	            .spawn(move || {
56	                let rt = match tokio::runtime::Builder::new_current_thread()
57	                    .enable_all()
58	                    .build()
59	                {
60	                    Ok(rt) => rt,
61	                    Err(e) => {
62	                        let _ = tx.send(Err(format!("tokio runtime build failed: {e}")));
63	                        return;
64	                    }
65	                };
66	
67	                rt.block_on(async move {
68	                    let tray = VibeTray {
69	                        open_window: Arc::clone(&open_window_clone),
70	                        quit_window: Arc::clone(&quit_window_clone),
71	                        state: Arc::new(Mutex::new(TrayState::default())),
72	                    };
73	                    let state_ref = Arc::clone(&tray.state);
74	
75	                    match tray.spawn().await {
76	                        Ok(handle) => {
77	                            let _ = tx.send(Ok(()));
78	
79	                            // Spawn the poll loop inside the same tokio runtime.
80	                            let poll_handle = handle.clone();
81	                            tokio::spawn(async move {
82	                                loop {
83	                                    tokio::time::sleep(tokio::time::Duration::from_secs(1)).await;
84	
85	                                    let status = query_status();
86	                                    let new_daemon_state = status.as_ref().map(|s| s.state.clone());
87	                                    let new_active_mode = status.as_ref().map(|s| s.active_mode.clone());
88	                                    let new_active_profile = status.and_then(|s| s.active_profile);
89	                                    // Read profile list from disk on each tick — cheap stat, no daemon needed.
90	                                    let new_profiles = load_profiles();
91	
92	                                    // Only push a D-Bus update when the visible state actually changed.
93	                                    let changed = {
94	                                        let s = state_ref.lock().await;
95	                                        s.daemon_state != new_daemon_state
96	                                            || s.active_profile != new_active_profile
97	                                            || s.profiles != new_profiles
98	                                            || s.active_mode != new_active_mode
99	                                    };
100	
101	                                    if changed {
102	                                        poll_handle
103	                                            .update(|tray: &mut VibeTray| {
104	                                                if let Ok(mut s) = tray.state.try_lock() {
105	                                                    s.daemon_state = new_daemon_state.clone();
106	                                                    s.active_profile = new_active_profile.clone();
107	                                                    s.profiles = new_profiles.clone();
108	                                                    s.active_mode = new_active_mode.clone();
109	                                                }
110	                                            })
111	                                            .await;
112	                                    }
113	                                }
114	                            });
115	
116	                            std::future::pending::<()>().await;
117	                        }
118	                        Err(e) => {
119	                            let _ = tx.send(Err(format!("tray spawn failed: {e}")));
120	                        }
121	                    }
122	                });
123	            })
124	            .ok()?;
125	
126	        match rx.recv() {
127	            Ok(Ok(())) => Some(TrayHandle {
128	                open_window,
129	                quit_window,
130	                _thread: thread,
131	            }),
132	            Ok(Err(e)) => {
133	                tracing::warn!(reason = %e, "System tray unavailable");
134	                None
135	            }
136	            Err(_) => None,
137	        }
138	    }
