153	/// Return the XDG/FreeDesktop icon name for a given daemon state.
154	///
155	/// `None` means the daemon is not running — treat the same as Muted so the
156	/// tray icon makes it obvious the mic is inactive.  `Listening` gets a
157	/// distinct "high" variant to distinguish the wake-word window from idle.
158	pub(crate) fn icon_name_for_state(state: Option<&DaemonState>) -> &'static str {
159	    match state {
160	        None | Some(DaemonState::Muted) => "audio-input-microphone-muted",
161	        Some(DaemonState::Idle) | Some(DaemonState::Recording) => "audio-input-microphone",
162	        Some(DaemonState::Listening) => "audio-input-microphone-high",
163	    }
164	}
