166	/// Build the tooltip description string for a given daemon state and activation mode.
167	///
168	/// Extracted as a free function (mirroring [`icon_name_for_state`]) so it is unit-testable
169	/// without constructing any tray state or D-Bus connection.
170	pub(crate) fn tooltip_description_for(
171	    state: Option<&DaemonState>,
172	    mode: Option<&ActivationMode>,
173	) -> String {
174	    match state {
175	        None => "Not running".into(),
176	        Some(DaemonState::Idle) => match mode {
177	            Some(ActivationMode::Ptt) => "Idle — waiting for PTT key".into(),
178	            Some(ActivationMode::Wake) => "Idle — listening for wake word".into(),
179	            None => "Idle".into(),
180	        },
181	        Some(DaemonState::Muted) => "Muted".into(),
182	        Some(DaemonState::Listening) => "Listening\u{2026}".into(),
183	        Some(DaemonState::Recording) => "Recording\u{2026}".into(),
184	    }
185	}
